<template>
    <view class="container">
        <view class="listContent">
            <u-swipe-action autoClose>
                <u-swipe-action-item v-for="(item,index) in array" :options="options1" :key="index"  @click="handleClick(index)">
                    <view class="swipe-action u-border-top u-border-bottom">
                        <view class="swipe-action__content">
                            <view class="item">
                                <view class="itemLeft">
                                    <image src="../../../static/icons/record1.png" mode=""></image>
                                </view>
                                <view class="itemRight" v-text="item.date"></view>
                            </view>

                            <view class="item">
                                <view class="itemLeft">
                                    <image src="../../../static/icons/record2.png" mode=""></image>
                                </view>
                                <view class="itemRight" v-text="item.menu_name"></view>
                            </view>

                            <view class="item">
                                <view class="itemContent">
                                    <view class="itemLeft">
                                        <image src="../../../static/icons/record3.png" mode=""></image>
                                    </view>
                                    <view class="itemRight" v-text="item.member_name"></view>
                                </view>
                                <view class="coin">
                                    <view class="coni" v-text="toUp(item.card_type)"></view>
                                    <view class="count" v-text="item.card_count"></view>
                                </view>
                            </view>
                            <view class="item" v-for="ite,idx in item.coupons">
                                <view class="itemLeft">
                                    <image src="../../../static/icons/record4.png" mode=""></image>
                                </view>
                                <view class="itemRight" v-text="ite"></view>
                            </view>
                        </view>
                    </view>
                </u-swipe-action-item>
            </u-swipe-action>
        </view>
        <mod v-if="showModule" @getStatus="getStatus" :config="configs"></mod>
    </view>
</template>

<script>
    import mod from "@/components/mod.vue"
    import {getAppointmentList,getCome} from "@/api/index.js"
    
    export default {
        components:{
            mod
        },
        data() {
            return {
                options1: [{
                    text: '削除',
                    style: {
                        backgroundColor: '#D93025'
                    }
                }],
                showModule:false,
                configs:{},
                current:0,
                array: []
            }
        },
        onLoad(options) {
            let that = this
            that.getList(options.id)
        },
        methods: {
            getList(id){
                let that = this
                let data = {}
                data.id = id
                data.type = "list"
                getCome(data).then((res) => {
                    console.log(res)
                    if(res.code == 200){
                        that.array = res.data.orders
                    }
                })
            },
            toUp(e){
                return e.toUpperCase()
            },
            handleClick(e){
                console.log(e)
                let obj = {}
                obj.title = 'この情報を削除しますか？'
                obj.content = '削除すると、この情報は完全に削除されます。'
                obj.confirm = true
                obj.cancel = true
                obj.confirmText = "情報を削除"
                obj.cancelText = "キャンセル"
                this.configs = obj
                this.current = e
                this.showModule = true
            },
            getStatus(e){
                console.log(e)
            }
        }
    }
</script>

<style lang="scss">
    .swipe-action__content {
        box-sizing: border-box;
        padding: 20upx 0;
    }
    .itemRight{
        font-family: Hiragino Sans-W3, Hiragino Sans;
    }
    .item {
        display: flex;
        align-items: center;
        box-sizing: border-box;
        padding: 20upx 0;

        .itemContent {
            display: flex;
            align-items: center;
        }

        .coin {
            display: flex;
            align-items: center;
            margin-left: 276upx;

            .coni {
                width: 40upx;
                height: 40upx;
                background: #D93025;
                color: #fff;
                text-align: center;
                line-height: 40upx;
                font-size: 28upx;
                font-weight: bold;
                border-radius: 50%;
                margin-right: 20upx;
            }

            .count {
                font-size: 28upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                color: #D93025;
            }

        }

        .itemLeft {
            width: 40upx;
            height: 40upx;
            margin-right: 20upx;

            image {
                width: 100%;
                height: 100%;
            }
        }
    }
</style>
